#!/usr/bin/env node

const cli = require('@vbarbarosh/node-helpers/src/cli');
const format_bytes = require('@vbarbarosh/node-helpers/src/format_bytes');
const fs = require('fs');
const fs_size = require('@vbarbarosh/node-helpers/src/fs_size');
const stream = require('stream');
const stream_map = require('@vbarbarosh/node-helpers/src/stream_map');
const stream_progress = require('@vbarbarosh/node-helpers/src/stream_progress');
const stream_xml_parse = require('@vbarbarosh/node-helpers/src/stream_xml_parse');

cli(main);

async function main()
{
    const input_file = '/tmp/psd7003.xml';
    await stream.promises.pipeline(
        fs.createReadStream(input_file),
        stream_progress({total: await fs_size(input_file), user_friendly_status}),
        stream_xml_parse(['ProteinDatabase', 'ProteinEntry']),
        stream_map(v => `${JSON.stringify(v)}\n`),
        fs.createWriteStream('out.ndjson')
    );
}

function user_friendly_status(s)
{
    console.log(s, `mem=${format_bytes(process.memoryUsage().heapUsed)}`);
}

#!/usr/bin/env node

const cli = require('@vbarbarosh/node-helpers/src/cli');
const format_bytes = require('@vbarbarosh/node-helpers/src/format_bytes');
const http_get_stream = require('@vbarbarosh/node-helpers/src/http_get_stream');
const perf_end_human = require('@vbarbarosh/node-helpers/src/perf_end_human');
const perf_start = require('@vbarbarosh/node-helpers/src/perf_start');
const stream = require('stream');
const stream_gunzip = require('@vbarbarosh/node-helpers/src/stream_gunzip');
const stream_progress = require('@vbarbarosh/node-helpers/src/stream_progress');
const stream_xml_analyze = require('@vbarbarosh/node-helpers/src/stream_xml_analyze');

cli(main);

async function main()
{
    const time0 = perf_start();

    // const input_url = 'https://dumps.wikimedia.org/enwiki/latest/enwiki-latest-pages-logging1.xml.gz';
    const input_url = 'https://aiweb.cs.washington.edu/research/projects/xmltk/xmldata/data/pir/psd7003.xml.gz';
    await user_friendly_status(`🌎 Connecting to ${input_url}`);
    const rs = await http_get_stream(input_url);
    const [out] = await stream.compose(
        rs,
        stream_progress({total: rs.total, user_friendly_status}),
        stream_gunzip(),
        stream_xml_analyze()
    ).toArray();

    console.log(out);
    console.log(`🎉 Done in ${perf_end_human(time0)}`);
}

function user_friendly_status(s)
{
    console.log(s, `mem=${format_bytes(process.memoryUsage().heapUsed)}`);
}

