#!/usr/bin/env node

const Promise = require('bluebird');
const cli = require('@vbarbarosh/node-helpers/src/cli');
const stream = require('stream');
const stream_discard = require('@vbarbarosh/node-helpers/src/stream_discard');
const stream_progress = require('@vbarbarosh/node-helpers/src/stream_progress');

cli(main);

async function main()
{
    const total = 1E7;
    const rs = stream.Readable.from(gen(total));
    await stream.promises.pipeline(
        rs,
        stream_progress({total, interval: 100}),
        stream_discard()
    );
    console.log('🎉 Done');
}

async function* gen(total)
{
    for (let i = 0; i < total; ++i) {
        yield Buffer.from([i]);
        if (i % 1E3 === 0) {
            await Promise.delay(0);
        }
    }
}

#!/usr/bin/env node

const cli = require('@vbarbarosh/node-helpers/src/cli');
const http_get_buffer = require('@vbarbarosh/node-helpers/src/http_get_buffer');
const perf_end_human = require('@vbarbarosh/node-helpers/src/perf_end_human');
const perf_start = require('@vbarbarosh/node-helpers/src/perf_start');
const stream = require('stream');
const stream_parse_csv = require('@vbarbarosh/node-helpers/src/stream_parse_csv');

cli(main);

async function main()
{
    const time0 = perf_start();

    const s = await http_get_buffer('https://www.bnm.md/en/export-official-exchange-rates?date=31.12.2024');

    const rows = await stream.Readable.from(s).compose(stream_parse_csv({delimiter: ';', relax_column_count: true})).toArray();
    if (rows.length === 1) {
        throw new Error(rows[0][0]);
    }

    const out = {};
    rows.forEach(function (cols) {
        switch (cols.length) {
        case 1:
            break;
        case 2:
            out[cols[0]] = cols[1];
            break;
        case 5:
            switch (cols[2]) {
            case 'USD':
            case 'EUR':
                out[cols[2].toLowerCase()] = +cols[4].replace(',', '.');
                break;
            }
            break;
        default:
            throw new Error(`Unrecognized number of columns: ${cols.length}`);
        }
    });
    out.date = rows[0][1].replace(/^(\d\d).(\d\d).(\d\d\d\d)$/, '$3/$2/$1');
    delete out.abbr;
    delete out[''];
    delete out['Data source:'];
    delete out['Date:'];
    delete out['Hour:'];

    console.log(out);
    console.log(`🎉 Done in ${perf_end_human(time0)}`);
}

const Promise = require('bluebird');
const cli = require('@vbarbarosh/node-helpers/src/cli');
const random_int = require('@vbarbarosh/node-helpers/src/random_int');
const stream = require('stream');
const stream_chunk = require('@vbarbarosh/node-helpers/src/stream_chunk');
const stream_each = require('@vbarbarosh/node-helpers/src/stream_each');
const stream_map_parallel = require('@vbarbarosh/node-helpers/src/stream_map_parallel');
const stream_progress = require('@vbarbarosh/node-helpers/src/stream_progress');

cli(main);

async function main()
{
    const input = Array(100).fill().map((v,i) => i);
    await stream.promises.pipeline(
        stream.Readable.from(input),
        stream_map_parallel({
            concurrency: 10,
            handler: async function (item) {
                await Promise.delay(random_int(100, 5000));
                return item;
            },
        }),
        stream_progress({
            objectMode: true,
            total: input.length,
            user_friendly_status,
        }),
        stream_chunk(10),
        stream_each(function (items) {
            console.log(items);
        }),
    );
    console.log('🎉 Done');
}

function user_friendly_status(s)
{
    console.log(s);
}

