function _try(callback, default_value)
{
    try {
        return callback();
    }
    catch {
        return default_value;
    }
}

module.exports = _try;

/**
 * Split an array into chunks.
 *
 * @param array
 * @param limit
 * @returns {*[]}
 */
function array_chunk(array = [], limit = 1)
{
    if (limit < 1) {
        throw new Error('Limit value should be at least 1');
    }

    const out = [];
    for (let i = 0, end = array.length; i < end; i += limit) {
        out.push(array.slice(i, i + limit));
    }
    return out;
}

module.exports = array_chunk;

const clamp = require('./clamp');

/**
 * Split an array into up to `max_chunks` balanced chunks, while ensuring that
 * each chunk contains at least `min_items_per_chunk` items (when possible).
 *
 * The function distributes items as evenly as possible:
 * - Chunk sizes differ by at most 1 item.
 * - The number of chunks never exceeds `max_chunks`.
 *
 * Originally designed for distributing workload across threads
 * (e.g. `array_chunk_balanced(jobs, max_threads, min_jobs_per_thread)`).
 *
 * Edge cases:
 * - If the input array is empty → returns [].
 * - If there are too few items to satisfy `min_items_per_chunk`, even for a single
 *   chunk, all items are placed into one chunk.
 *
 * @param {Array} array
 * @param {number} max_chunks
 * @param {number} min_items_per_chunk
 * @returns {Array<Array>}
 */
function array_chunk_balanced(array = [], max_chunks = 1, min_items_per_chunk = 1)
{
    const total_chunks = clamp(1, max_chunks, Math.floor(array.length / min_items_per_chunk));
    const items_per_chunk = Math.floor(array.length / total_chunks);
    let extra = array.length % total_chunks;

    const out = [];
    for (let i = 0; i < array.length; ) {
        const size = items_per_chunk + (extra ? 1 : 0);
        out.push(array.slice(i, i + size));
        i += size;
        if (extra) {
            extra--;
        }
    }
    return out;
}

module.exports = array_chunk_balanced;

const round = require('./round');

const EPS = 0.00001;

function array_fps(duration_sec, fps)
{
    const total_frames = Math.floor(duration_sec * fps);

    if (total_frames <= 1) {
        return [0];
    }

    const out = [];
    for (let i = 0; i < total_frames; ++i) {
        out.push(round((i / (total_frames - 1)) * (duration_sec - EPS), EPS));
    }
    return out;
}

module.exports = array_fps;

const math_gcd = require('./math_gcd');

// https://stackoverflow.com/a/39764792/1478566
function array_gcd(array, read = Number)
{
    // 0 is the identity of gcd (gcd(0, x) = x); it also makes an empty
    // array return 0 instead of throwing
    return array.map(v => read(v)).reduce((a,b) => math_gcd(a, b), 0);
}

module.exports = array_gcd;

/**
 * Group items by a common key and return an array of groups.
 *
 * @alternative Map.groupBy(items, read)
 */
function array_group(array, read)
{
    const map = new Map();
    array.forEach(function (item) {
        const key = read(item);
        if (!map.has(key)) {
            map.set(key, {key, items: []});
        }
        map.get(key).items.push(item);
    });
    return map.values().toArray();
}

module.exports = array_group;

src.markdown:
Groups items by the key returned from `read(item)` and returns an array of
`{key, items}` groups, in the order each key was first seen. Keys are compared
with `Map` semantics, so any value type works as a key.

```js
array_group([{t: 'a', v: 1}, {t: 'b', v: 2}, {t: 'a', v: 3}], x => x.t)
// [
//     {key: 'a', items: [{t: 'a', v: 1}, {t: 'a', v: 3}]},
//     {key: 'b', items: [{t: 'b', v: 2}]},
// ]
```

Native alternative: `Map.groupBy(items, read)`. See `array_group_map` for the
same grouping returned as an object keyed by `key`.

src.source_code:
/**
 * Group items by common key and return an object of items grouped by key.
 *
 * @param array
 * @param read
 * @returns {{}}
 */
function array_group_map(array, read)
{
    const out = {};
    array.forEach(function (item) {
        const key = read(item);
        out[key] = out[key] || {key, items: []};
        out[key].items.push(item);
    });
    return out;
}

module.exports = array_group_map;

src.markdown:
Groups items by the key returned from `read(item)` and returns a plain object
mapping each key to a `{key, items}` group. Keys are used as object properties,
so they are coerced to strings.

```js
array_group_map([{t: 'a', v: 1}, {t: 'b', v: 2}, {t: 'a', v: 3}], x => x.t)
// {
//     a: {key: 'a', items: [{t: 'a', v: 1}, {t: 'a', v: 3}]},
//     b: {key: 'b', items: [{t: 'b', v: 2}]},
// }
```

See `array_group` for the same grouping returned as an array of groups.

