const identity = require('./identity');

/**
 * Usage:
 *     array_index(items, v => v.name)
 *
 * Seems, there is a native way to do it:
 *     Object.fromEntries(items.map(v => [v.name, v]));
 */
function array_index(array, read = identity)
{
    const out = {};
    array.forEach(v => out[read(v)] = v);
    return out;
}

module.exports = array_index;

const math_lcm = require('./math_lcm');

function array_lcm(array, read = Number)
{
    // 1 is the identity of lcm (lcm(1, x) = x); it also makes an empty
    // array return 1 instead of throwing
    return array.map(v => read(v)).reduce((a,b) => math_lcm(a, b), 1);
}

module.exports = array_lcm;

const identity = require('./identity');

/**
 * Returns the first element in the array with the maximal weight
 */
function array_max(array, read = identity)
{
    let out = null;
    let max = null;
    let seeded = false;
    array.forEach(function (item) {
        const weight = read(item);
        // NaN compares false with everything: seeding max with it would
        // make every subsequent comparison fail
        if (Number.isNaN(weight)) {
            return;
        }
        if (!seeded || max < weight) {
            seeded = true;
            max = weight;
            out = item;
        }
    });
    return out;
}

module.exports = array_max;

const identity = require('./identity');

/**
 * Returns the first element in the array with the minimal weight
 */
function array_min(array, read = identity)
{
    let out = null;
    let min = null;
    let seeded = false;
    array.forEach(function (item) {
        const weight = read(item);
        // NaN compares false with everything: seeding min with it would
        // make every subsequent comparison fail
        if (Number.isNaN(weight)) {
            return;
        }
        if (!seeded || min > weight) {
            seeded = true;
            min = weight;
            out = item;
        }
    });
    return out;
}

module.exports = array_min;

// https://stackoverflow.com/a/37580979/23502239
function array_permutations(array, k = array.length)
{
    if (k !== array.length) {
        return array_permutations_k(array, k);
    }

    // Heap's algorithm permutes in place: work on a copy, the caller's
    // array must not be left in an arbitrary permuted state.
    array = array.slice();

    let length = array.length;
    let out = [array.slice()];
    let c = new Array(length).fill(0);
    let i = 1, kk, p;

    while (i < length) {
        if (c[i] < i) {
            kk = i % 2 && c[i];
            p = array[i];
            array[i] = array[kk];
            array[kk] = p;
            ++c[i];
            i = 1;
            out.push(array.slice());
        }
        else {
            c[i] = 0;
            ++i;
        }
    }
    return out;
}

function array_permutations_k(array, k)
{
    if (k === 0) {
        return [
            []
        ];
    }
    if (array.length < k) {
        return [];
    }

    const out = [];
    for (let i = 0; i < array.length; i++) {
        const rest = array.slice(0, i).concat(array.slice(i + 1));
        for (const perm of array_permutations(rest, k - 1)) {
            out.push([array[i], ...perm]);
        }
    }
    return out;
}

module.exports = array_permutations;

/**
 * Shuffles an array using Durstenfeld shuffle algorithm.
 *
 * Note: This function performs shuffle in-place. In order
 * to get a shuffled copy use call slice before calling, e.g.
 * array_shuffle(items.slice()).
 *
 * @param array
 * @returns array
 * @link https://stackoverflow.com/a/6274381/1478566
 * @link https://en.wikipedia.org/wiki/Fisher%E2%80%93Yates_shuffle
 */
function array_shuffle(array)
{
    for (let i = array.length; --i > 0; ) {
        const j = Math.floor(Math.random() * (i + 1));
        const x = array[i];
        array[i] = array[j];
        array[j] = x;
    }
    return array;
}

module.exports = array_shuffle;

const fcmp_default = require('./fcmp_default');
const fcmp_tuples = require('./fcmp_tuples');

/**
 * Sorts an array in place by the result of applying `fn` to each item,
 * using `fcmp` to compare the results.
 *
 * array_sort(items, v => v.name)
 * array_sort(items, v => [v.name])
 * array_sort(items, v => [v.age, v.name])
 */
function array_sort(array, mapper, fcmp = fcmp_default)
{
    const keys = new Map();
    return array.sort(function (a, b) {
        // A scalar key is a 1-tuple: fcmp_tuples on scalars would compare
        // nothing and silently leave the array unsorted
        if (!keys.has(a)) {
            const key = mapper(a);
            keys.set(a, Array.isArray(key) ? key : [key]);
        }
        if (!keys.has(b)) {
            const key = mapper(b);
            keys.set(b, Array.isArray(key) ? key : [key]);
        }
        return fcmp_tuples(keys.get(a), keys.get(b), fcmp);
    });
}

// function array_sort(array, fn = identity, fcmp = fcmp_default)
// {
//     return array.sort(function (a, b) {
//         return fcmp(fn(a), fn(b));
//     });
// }

module.exports = array_sort;

const fcmp_default = require('./fcmp_default');

/**
 * Sort items in an `array` at the same order as in `other`. Values which
 * are not in the `other` are added to the end of the result defined by `fcmp`.
 *
 * @param array
 * @param read
 * @param other
 * @param fcmp
 * @returns {*}
 */
function array_sort_other(array, read, other, fcmp = fcmp_default)
{
    // No-prototype object: with a plain {} the keys 'constructor',
    // 'toString', '__proto__', ... would collide with Object.prototype
    // members and corrupt the sort order.
    const other_map = Object.create(null);
    other.forEach((v,i) => other_map[v] = i + 1);
    return array.sort(function (a, b) {
        const ax = other_map[read(a)];
        const bx = other_map[read(b)];
        if (ax && bx) {
            return ax - bx;
        }
        if (ax) {
            return -1;
        }
        if (bx) {
            return 1;
        }
        return fcmp(a, b);
    });
}

