const ExitCodeError = require('./errors/ExitCodeError');
const Promise = require('bluebird');

/**
 * Entry point for Node CLI apps
 */
function cli(main, report = error => console.error(error))
{
    // https://stackoverflow.com/a/46916601/1478566
    const timer = setInterval(v => v, 1E9);

    // Promise.resolve(main()) would evaluate main() before wrapping:
    // a synchronous throw would bypass report() and the exit code handling
    Promise.try(main).then(resolve, reject);

    function resolve() {
        clearInterval(timer);
    }
    function reject(error) {
        clearInterval(timer);
        report(error);
        if (error instanceof ExitCodeError) {
            process.exit(error.exit_code);
        }
        else {
            process.exit(1);
        }
    }
}

module.exports = cli;

src.markdown:
Entry point for Node CLI apps. Runs `main` (sync or async), keeps the event
loop alive until it settles, and turns a failure into a proper exit code.

- Resolves → the process exits naturally with code `0`.
- Rejects or throws → the error is passed to `report` (default
  `console.error`), then `process.exit(1)`.
- An `ExitCodeError` exits with its `exit_code` instead of `1`.
- Synchronous throws from `main` are handled the same way as rejections —
  they do not bypass `report` or the exit code handling.

```js
cli(async function main() {
    // ...
});
```

