function escape_content_disposition(s)
{
    const out = s.replaceAll('\\', '\\\\')
        .replaceAll('"', '\\"')
        .replaceAll('%', '\\%')
        .replaceAll('\n', '%x0A')
        .replaceAll('\0', '%x00');
