const is_fn_gen_async = require('@vbarbarosh/type-helpers/src/is_fn_gen_async');

/**
 * - Run until `spawn` return `null`.
 * - Keep no more than `concurrency` number of workers at a time.
 *
 * ⚠️ Warning: `spawn` should not be async function (async functions are always return `promise`).
 *    Instead, it should be a simple function returning either `null` or a `promise`.
 */
async function parallel({concurrency, spawn, progress})
{
    if (is_fn_async(spawn) || is_fn_gen_async(spawn)) {
        throw new Error('[spawn] should not be async function. Instead, it should be a simple function returning either [null] or a [promise].');
    }
    const running = [];
    return new Promise(function (resolve, reject) {
        let failed = false;
        const timer = setInterval(tick, 1000);
        schedule();
        if (running.length) {
            tick();
        }
        function schedule() {
            while (running.length < concurrency) {
                if (failed) {
                    break;
                }
                let w;
                try {
                    w = spawn();
                }
                catch (error) {
                    // A synchronous throw from spawn must go through fail():
                    // when schedule() runs inside a resolved() handler it
                    // would otherwise become an unhandled rejection and this
                    // promise would never settle (and the timer would leak).
                    fail(error);
                    return;
                }
                if (!w) {
                    break;
                }
                const item = Promise.resolve(w).then(resolved, fail);
                running.push(item);
                function resolved() {
                    if (failed) {
                        return;
                    }
                    const i = running.indexOf(item);
                    if (i === -1) {
                        throw new NotImplemented();
                    }
                    running.splice(i, 1);
                    schedule();
                }
            }
            if (running.length === 0 && !failed) {
                tick();
                clearInterval(timer);
                resolve();
            }
        }
        function fail(error) {
            if (failed) {
                return;
            }
            failed = true;
            running.splice(0, running.length);
            clearInterval(timer);
            reject(error);
        }
        function tick() {
            if (progress) {
                progress(running);
            }
        }
    });
}

module.exports = parallel;

function parse_bytes(bytes)
{
    const sizes = ['B', 'KB', 'MB', 'GB', 'TB', 'PB'];
    if (typeof bytes !== 'string') {
        return Number.NaN;
    }
    // Anchored: trailing garbage ('12KB34') is NaN rather than 12KB. A bare
    // number means bytes; whitespace around and between number and unit is ok
    const m = bytes.toUpperCase().match(/^\s*(\d+(?:[.]\d+)?)\s*((?:[KMGTP]I?)?B)?\s*$/);
    if (!m) {
        return Number.NaN;
    }
    return Math.floor(m[1]*Math.pow(1024, sizes.indexOf((m[2] || 'B').replace('I', ''))));
}

module.exports = parse_bytes;

function parse_hms(expr)
{
    if (!expr && expr !== 0) {
        return 0;
    }

    expr = String(expr).trim();
    if (!expr) {
        return 0;
    }

    const parts = expr.split(':');

    let h = 0, m = 0, s;

    if (parts.length === 1) {
        // "SS(.fff)"
        s = parseFloat(parts[0]);
    }
    else if (parts.length === 2) {
        // "MM:SS(.fff)"
        m = parseFloat(parts[0]);
        s = parseFloat(parts[1]);
    }
    else if (parts.length === 3) {
        // "HH:MM:SS(.fff)"
        h = parseFloat(parts[0]);
        m = parseFloat(parts[1]);
        s = parseFloat(parts[2]);
    }
    else {
        return Number.NaN;
    }

    // Any failed numeric parse ⇒ NaN
    if ([h, m, s].some(n => Number.isNaN(n))) {
        return Number.NaN;
    }

    return h*3600 + m*60 + s;
}

module.exports = parse_hms;

function parse_http_content_range(value)
{
    // Content-Range: bytes 262144000-272629759/5037662208
    // Content-Range: bytes */5037662208 (unsatisfied range → first/last are null)
    // Content-Range: bytes 0-499/* (unknown total → total is null)
    const m = value.match(/^(\w+)\s+(?:(\d+)-(\d+)|[*])[/](?:(\d+)|[*])$/);
    // "*/*" is not in the RFC 7233 grammar: an unsatisfied range must state
    // the complete length
    if (!m || (m[2] === undefined && m[4] === undefined)) {
        throw new Error(`Invalid Content-Range: [${value}]`);
    }
    const type = m[1];
    const first = m[2] === undefined ? null : +m[2];
    const last = m[3] === undefined ? null : +m[3];
    const total = m[4] === undefined ? null : +m[4];
    return {type, first, last, total};
}

module.exports = parse_http_content_range;

