    const {
        poll_message,
        push_response,
        process_message,
        log_waiter_begin,
        log_waiter_end,
        log_waiter_sleep,
        log_waiter_rpush,
        log_waiter_error,
        log_waiter_error_parse,
        log_waiter_error_no_uid,
    } = options;

    log(`[${log_waiter_begin}] v${version}`);
    try {
