            // const message_string = await redis.lpop_p(redis_input_queue);
            const message = await poll_message();
            if (!message) {
                const ms = random_int(500, 1500);
                log(`[${log_waiter_sleep}] ${ms}ms`);
                await Promise.delay(ms);
                continue;
            }

            try {
                const uid = message.uid;

