                await push_response({uid: message.uid, version, type: 'resolve', value});

                log(`[${log_waiter_rpush}]`);
            }
            catch (error) {
                const response = {uid: message.uid, version, type: 'reject', value: `${(error && (error.stack || error.message)) || 'Error N/A'}`};
