        write: async function (chunk, encoding, callback) {
            let done = 0;
            streams.forEach(function (stream) {
                stream.write(chunk, encoding, function (error) {
                    if (++done === streams.length || error) {
                        callback(error);
                        callback = ignore;
                    }
