// [Merger] Merging formats into "xxxxxxxxxxxxxxx.webm"
// Deleting original file xxxxxxxxxxxxxxx.f251.webm (pass -k to keep)
// Deleting original file xxxxxxxxxxxxxxx.f248.webm (pass -k to keep)

function stream_ytdlp_progress()
{
    let last = {};
    let current_part = 1;
    const downloading_formats = [];
    return stream.compose(
        stream_lines(),
        stream_map(function (line) {
            let m;
            if (m = line.match(/^\[info] \S+: Downloading \d+ format\(s\): (.+)$/)) {
                downloading_formats.push(...m[1].split('+'));
                return false;
            }
            if (m = line.match(/^\[download] Destination: .*f(\d+)\.[^.]+/)) {
                current_part = downloading_formats.indexOf(m[1]) + 1;
                return false;
            }
            if (line.match(/^\[Merger]/i)) {
                last.merging = true;
                return last;
            }
            if (m = line.match(/^\[download] (.*) of (.*) at (.*) ETA (.*)$/)) {
                const percentage = parseFloat(m[1].trim())/100;
                const total = parse_bytes(m[2].trim());
                const speed = m[3].trim().replace('i', '');
                const eta = m[4].trim();
                return last = {
                    current_part,
                    total_parts: downloading_formats.length,
                    perc: format_percents(percentage),
                    done: format_bytes(percentage*total),
                    total: format_bytes(total),
                    speed: speed.toLowerCase().includes('unknown') ? '~' : speed,
                    eta: eta.toLowerCase().includes('unknown') ? '~' : eta,
                    merging: false,
                };
            }
            return false;
        }),
        stream_filter(v => v),
    );
}

module.exports = stream_ytdlp_progress;

// PHP’s strtr tries the longest possible key first when multiple keys overlap.
// echo strtr("hello", ["he" => "X", "hell" => "Y"]);
function strtr(subject, map)
{
    // Single pass, like PHP: replaced text is never scanned again
    const keys = Object.keys(map).filter(v => v.length).sort(fcmp);
    let out = '';
    for (let i = 0; i < subject.length; ) {
        const key = keys.find(v => subject.startsWith(v, i));
        if (key) {
            out += map[key];
            i += key.length;
        }
        else {
            out += subject[i];
            i++;
        }
    }
    return out;
    function fcmp(b, a) {
        return a.length - b.length;
    }
}

module.exports = strtr;

/**
 * Ensure that only one event was fired for each ms.
 *
 * @link https://stackoverflow.com/questions/25991367/difference-between-throttling-and-debouncing-a-function
 */
function throttle(ms, fn)
{
    let timer = null;
    let last_value = undefined;
    run.fire = fire;
    return run;
    function run(value) {
        last_value = value;
        if (timer === null) {
            timer = setTimeout(fire, ms)
        }
    }
    function fire() {
        if (timer === null) {
            return;
        }
        clearTimeout(timer);
        timer = null;
        const tmp = last_value;
        last_value = undefined;
        return fn(tmp);
    }
}

module.exports = throttle;

const querystring = require('querystring');

/**
 * Replace unnecessary encodes symbols with chars. The returned url will be
 * more human-friendly, at the same time it will still be valid url.
 */
function urlclean(url)
{
    // The #fragment is not part of the query string: without splitting it
    // off first it would be percent-encoded into the last query value.
    const h = url.indexOf('#');
    const hash = (h === -1) ? '' : url.slice(h);
    if (hash) {
        url = url.slice(0, h);
    }
    const i = url.indexOf('?') + 1;
    if (i) {
        const s = querystring.stringify(querystring.parse(url.slice(i)), '&', '=', {
            encodeURIComponent: function (v) {
                return encodeURIComponent(v).replaceAll('%3A', ':').replaceAll('%2F', '/');
            },
        });
        return url.slice(0, i) + s + hash;
    }
    return url + hash;
}

module.exports = urlclean;

/**
 * Set, change, or remove query string parameters.
 *
 * urlmod('', {a: 1})           '?a=1'  set
 * urlmod('?a=1', {a: 2})       '?a=2'  change
 * urlmod('?a=1', {a: null})    ''      remove
 */
function urlmod(url, params)
{
    const tmp_url = new URL(url||'', 'xxx://___base___/');
    const tmp_search = tmp_url.searchParams;
    Object.entries(params || {}).forEach(function ([key, value]) {
        switch (value) {
        case null:
        case undefined:
            tmp_search.delete(key);
            break;
        case true:
            tmp_search.set(key, 1);
            break;
        case false:
            tmp_search.set(key, 0);
            break;
        default:
            tmp_search.set(key, value);
            break;
        }
    });
    if (url && url[0] === '/' && url[1] === '/') {
        // Protocol-relative url: the fake base host was replaced by the
        // real one, only the fake scheme is left to strip.
        return tmp_url.toString().replace(/^xxx:/, '');
    }
    if (url && url[0] === '/') {
        return tmp_url.toString().replace(/^xxx:\/\/___base___/, '');
    }
    return tmp_url.toString().replace(/^xxx:\/\/___base___\//, '');
}

module.exports = urlmod;

function urlparts(url)
{
    const tmp = url instanceof URL
        ? url
        : new URL((typeof url === 'string' ? url : ''), 'fake://fake/');
    return {
        href: tmp.href,
        protocol: tmp.protocol,
        hostname: tmp.hostname,
        username: tmp.username,
        password: tmp.password,
        host: tmp.host,
        port: tmp.port,
        path: tmp.pathname,
        search: tmp.search,
        hash: tmp.hash,
    };
}

module.exports = urlparts;

