const Promise = require('bluebird');

/**
 * Wait while `fn` returns a truthy value; resolve as soon as it turns falsy.
 *
 * W A R N I N G
 * This method was designed mainly for prototyping (where code cleanliness is important).
 * It might drastically decrease performance.
 */
function wait_while(fn)
{
    return new Promise(function (resolve, reject) {
        setTimeout(tick, 1);
        async function tick() {
            try {
                if (await fn()) {
                    setTimeout(tick, 1);
                }
                else {
                    resolve();
                }
            }
            catch (error) {
                reject(error);
            }
        }
    });
}

module.exports = wait_while;

const Promise = require('bluebird');

/**
 * Wait for a Node-like function to finish (which will call `callback`
 * with 2 arguments: `error` and `value`).
 *
 * await waitcb(cb => fs.writeFile('a', 'hello\n', cb));
 */
function waitcb(fn)
{
    return new Promise(function (resolve, reject) {
        fn(function (error, out) {
            error ? reject(error) : resolve(out);
        });
    });
}

module.exports = waitcb;
